import{_ as r,o as t,c as a,ai as s}from"./chunks/framework.LYGRWSbL.js";const p=JSON.parse('{"title":"Se présenter","description":"","frontmatter":{},"headers":[],"relativePath":"module-1-fondations/se-presenter.md","filePath":"module-1-fondations/se-presenter.md","lastUpdated":1773229777000}'),i={name:"module-1-fondations/se-presenter.md"};function n(o,e,l,d,m,u){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="se-presenter" tabindex="-1">Se présenter <a class="header-anchor" href="#se-presenter" aria-label="Permalink to “Se présenter”">​</a></h1><p><strong>Prérequis :</strong> <a href="./salutations.html">Salutations</a></p><p><strong>Objectif :</strong> dire qui tu es, d&#39;ou tu viens, ton age et ce que tu fais - les bases d&#39;une premiere conversation.</p><p>Se presenter en allemand suit des structures simples et regulieres. Les quelques phrases de cette lecon te permettront de tenir une vraie conversation courte.</p><h2 id="donner-son-nom" tabindex="-1">Donner son nom <a class="header-anchor" href="#donner-son-nom" aria-label="Permalink to “Donner son nom”">​</a></h2><p>Il existe trois facons de dire son nom - toutes sont correctes :</p><div class="mt-4 grid gap-3"><div class="p-4 rounded-lg border border-gray-200"><div class="font-semibold text-gray-900">Ich heiße [prenom].</div><div class="text-sm text-gray-500 mt-1">Je m&#39;appelle [prenom]. - la forme la plus courante a l&#39;oral</div></div><div class="p-4 rounded-lg border border-gray-200"><div class="font-semibold text-gray-900">Ich bin [prenom].</div><div class="text-sm text-gray-500 mt-1">Je suis [prenom]. - direct et tres naturel</div></div><div class="p-4 rounded-lg border border-gray-200"><div class="font-semibold text-gray-900">Mein Name ist [prenom].</div><div class="text-sm text-gray-500 mt-1">Mon nom est [prenom]. - plus formel, souvent a l&#39;ecrit</div></div></div><p><strong>Pour demander le nom de quelqu&#39;un :</strong></p><ul><li><em>Wie heißt du ?</em> - Comment tu t&#39;appelles ? (informel)</li><li><em>Wie heißen Sie ?</em> - Comment vous appelez-vous ? (formel)</li></ul><h2 id="d-ou-viens-tu" tabindex="-1">D&#39;ou viens-tu ? <a class="header-anchor" href="#d-ou-viens-tu" aria-label="Permalink to “D&#39;ou viens-tu ?”">​</a></h2><div class="mt-4 grid gap-3"><div class="p-4 rounded-lg border border-gray-200"><div class="font-semibold text-gray-900">Ich komme aus [pays / ville].</div><div class="text-sm text-gray-500 mt-1">Je viens de [pays / ville]. - Ex : *Ich komme aus Frankreich.* / *Ich komme aus Paris.*</div></div><div class="p-4 rounded-lg border border-gray-200"><div class="font-semibold text-gray-900">Ich wohne in [ville].</div><div class="text-sm text-gray-500 mt-1">J&#39;habite a [ville]. - distingue ton origine de ton lieu de residence actuel</div></div></div><p><strong>Pour poser la question :</strong></p><ul><li><em>Woher kommst du ?</em> - D&#39;ou viens-tu ? (informel)</li><li><em>Woher kommen Sie ?</em> - D&#39;ou venez-vous ? (formel)</li></ul><h2 id="l-age" tabindex="-1">L&#39;age <a class="header-anchor" href="#l-age" aria-label="Permalink to “L&#39;age”">​</a></h2><p>En allemand, on utilise le verbe <em>sein</em> (etre), pas <em>avoir</em> comme en français.</p><div class="mt-4 p-4 rounded-lg border border-green-200 bg-green-50"><div class="font-semibold text-gray-900">Ich bin [nombre] Jahre alt.</div><div class="text-sm text-gray-600 mt-1">J&#39;ai [nombre] ans. - litteralement &quot;je suis [nombre] ans vieux&quot;</div><div class="text-sm text-gray-500 mt-2">Ex : <em>Ich bin dreißig Jahre alt.</em> - J&#39;ai 30 ans.</div></div><div class="info custom-block"><p class="custom-block-title">Avoir l&#39;age en allemand</p><p>En allemand on utilise <em>sein</em> (etre), pas <em>haben</em> (avoir) comme en français. <em>Ich bin 25 Jahre alt</em> signifie litteralement &quot;je suis 25 ans vieux&quot;. C&#39;est un des premiers reflexes a changer.</p></div><p><strong>Pour demander l&#39;age :</strong></p><ul><li><em>Wie alt bist du ?</em> - Quel age as-tu ? (informel)</li><li><em>Wie alt sind Sie ?</em> - Quel age avez-vous ? (formel)</li></ul><h2 id="la-profession" tabindex="-1">La profession <a class="header-anchor" href="#la-profession" aria-label="Permalink to “La profession”">​</a></h2><p>On dit simplement <em>Ich bin</em> + la profession, <strong>sans article</strong> (contrairement au français).</p><div class="warning custom-block"><p class="custom-block-title">Pas d&#39;article devant la profession</p><p>En français on dit &quot;je suis <strong>un</strong> professeur&quot;. En allemand on dit <em>Ich bin Lehrer</em> - sans <em>ein</em>. Ajouter l&#39;article serait une erreur typique de francophone.</p></div><div class="mt-4 grid gap-3"><div class="p-4 rounded-lg border border-gray-200"><div class="font-semibold text-gray-900">Ich bin Lehrer. / Ich bin Lehrerin.</div><div class="text-sm text-gray-500 mt-1">Je suis professeur (homme) / professeure (femme). La terminaison <strong>-in</strong> marque le feminin.</div></div><div class="p-4 rounded-lg border border-gray-200"><div class="font-semibold text-gray-900">Ich arbeite als [profession].</div><div class="text-sm text-gray-500 mt-1">Je travaille comme [profession]. - Ex : *Ich arbeite als Ingenieur.*</div></div><div class="p-4 rounded-lg border border-gray-200"><div class="font-semibold text-gray-900">Ich studiere [matiere].</div><div class="text-sm text-gray-500 mt-1">J&#39;etudie [matiere]. - Ex : *Ich studiere Informatik.* (J&#39;etudie l&#39;informatique.)</div></div></div><p><strong>Pour demander la profession :</strong></p><ul><li><em>Was machst du beruflich ?</em> - Qu&#39;est-ce que tu fais dans la vie ? (informel)</li></ul><h2 id="exemple-de-presentation-complete" tabindex="-1">Exemple de presentation complete <a class="header-anchor" href="#exemple-de-presentation-complete" aria-label="Permalink to “Exemple de presentation complete”">​</a></h2><div class="mt-4 p-5 rounded-xl border border-green-200 bg-green-50"><p class="font-medium text-gray-800 mb-1">Hallo ! Ich heiße Thomas. Ich komme aus Frankreich, aber ich wohne jetzt in Berlin. Ich bin achtundzwanzig Jahre alt und arbeite als Entwickler. Freut mich, dich kennenzulernen !</p><p class="text-sm text-gray-500 mt-3">Salut ! Je m&#39;appelle Thomas. Je viens de France mais j&#39;habite maintenant a Berlin. J&#39;ai 28 ans et je travaille comme developpeur. Ravi de te rencontrer !</p></div><blockquote><p><strong>Freut mich !</strong> signifie &quot;enchante(e)&quot; ou &quot;ravi(e) de te rencontrer&quot;. C&#39;est la formule standard pour conclure une presentation.</p></blockquote>',28)])])}const v=r(i,[["render",n]]);export{p as __pageData,v as default};
